let cropperPhoto = null;
let cropperSignature = null;
let cropperThumb = null;

function showCropperPopup(inputId, previewId, popupId) {

  const input = document.getElementById(inputId);

  if (!input.files || !input.files[0]) return;

  const reader = new FileReader();

  reader.onload = function (e) {

    const popup = document.getElementById(popupId);

    const cropperImage =
      document.getElementById(
        popupId === "cropperPopupPhoto"
          ? "cropperImagePhoto"
          : popupId === "cropperPopupSignature"
          ? "cropperImageSignature"
          : "cropperImageThumb"
      );

    cropperImage.src = e.target.result;

    popup.style.display = "flex";

    if (popupId === "cropperPopupPhoto") {

      if (cropperPhoto) cropperPhoto.destroy();

      cropperPhoto = new Cropper(cropperImage, {
        aspectRatio: NaN,
        viewMode: 1
      });

    } else if (popupId === "cropperPopupSignature") {

      if (cropperSignature) cropperSignature.destroy();

      cropperSignature = new Cropper(cropperImage, {
        aspectRatio: NaN,
        viewMode: 1
      });

    } else {

      if (cropperThumb) cropperThumb.destroy();

      cropperThumb = new Cropper(cropperImage, {
        aspectRatio: NaN,
        viewMode: 1
      });

    }

  };

  reader.readAsDataURL(input.files[0]);

  input.value = "";
}

function hideCropperPopup(popupId) {

  const popup = document.getElementById(popupId);

  popup.style.display = "none";

  if (popupId === "cropperPopupPhoto" && cropperPhoto) {
    cropperPhoto.destroy();
    cropperPhoto = null;
  }

  if (popupId === "cropperPopupSignature" && cropperSignature) {
    cropperSignature.destroy();
    cropperSignature = null;
  }

  if (popupId === "cropperPopupThumb" && cropperThumb) {
    cropperThumb.destroy();
    cropperThumb = null;
  }
}

function cropImage() {

  if (cropperPhoto) {

    const canvas = cropperPhoto.getCroppedCanvas();

    const img = document.getElementById("photoPreview");

    img.src = canvas.toDataURL();

    img.style.display = "block";

    const demo = document.getElementById("demoManLogoPhoto");

    if (demo) demo.style.display = "none";

    hideCropperPopup("cropperPopupPhoto");
  }

  if (cropperSignature) {

    const canvas = cropperSignature.getCroppedCanvas();

    const img = document.getElementById("signaturePreview");

    img.src = canvas.toDataURL();

    img.style.display = "block";

    const demo = document.getElementById("demoManLogoSignature");

    if (demo) demo.style.display = "none";

    hideCropperPopup("cropperPopupSignature");
  }

  if (cropperThumb) {

    const canvas = cropperThumb.getCroppedCanvas();

    const img = document.getElementById("thumbPreview");

    img.src = canvas.toDataURL();

    img.style.display = "block";

    const demo = document.getElementById("demoManLogoThumb");

    if (demo) demo.style.display = "none";

    hideCropperPopup("cropperPopupThumb");
  }
}

function resizeCroppedImage(
  previewId,
  width,
  height,
  fileName,
  infoId,
  targetKB
) {

  const preview = document.getElementById(previewId);

  if (!preview.src) return;

  const img = new Image();

  img.src = preview.src;

  img.onload = function () {

    const canvas = document.createElement("canvas");

    canvas.width = width;
    canvas.height = height;

    const ctx = canvas.getContext("2d");

    ctx.drawImage(img, 0, 0, width, height);

    let quality = 0.9;

    let dataUrl = canvas.toDataURL("image/jpeg", quality);

    const link = document.createElement("a");

    link.href = dataUrl;

    link.download = fileName;

    link.click();

    const info = document.getElementById(infoId);

    if (info) {

      const sizeKB = Math.round(dataUrl.length / 1024);

      info.innerHTML =
        `Width: ${width}px<br>
         Height: ${height}px<br>
         Size: ${sizeKB} KB`;

      info.style.display = "block";
    }
  };
}
